import{_ as e,o as a,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const n="/images/uebung001.jpg",g=JSON.parse('{"title":"Übung Lektion 3","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung03.md","filePath":"lektionen/uebung03.md"}'),t={name:"lektionen/uebung03.md"};function s(u,p,d,o,v,h){return a(),r("div",null,[...p[0]||(p[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-3" tabindex="-1">Übung Lektion 3 <a class="header-anchor" href="#ubung-lektion-3" aria-label="Permalink to &quot;Übung Lektion 3&quot;">​</a></h1><p>A) Setzen Sie folgende Sätze in den Plural:</p><p>1. dvijo brāhmaṇaḥ = द्विजो ब्राह्मणः</p><p>dvijā brāhmaṇāḥ.</p><p>द्वि्जा ब्राह्मणाः |</p><p>2. dvijaḥ kṣatriyaḥ = द्विजः क्षत्रियः</p><p>dvijāḥ kṣatriyāḥ.</p><p>द्विजाः क्षत्रियाः |</p><p>3. dvijo vaiśyaḥ = द्विजो वैश्यः</p><p>dvijā vaiśyāḥ.</p><p>द्विजा वैश्याः |</p><p>4. gurur brāhmaṇaḥ = गुरुर्ब्राह्मणः</p><p>guravo brāhmaṇāḥ.</p><p>गुरवो ब्राह्मणाः |</p><p>5. sādhur guruḥ = साधुर्गुरुः</p><p>sādhavo guravaḥ.</p><p>साधवो गुरवः |</p><p>6. guruḥ kaviḥ = गुरुः कविः</p><p>guravaḥ kavayaḥ.</p><p>गुरवः कवयः |</p><p>7. sādhvī brāhmaṇī = साध्वी ब्राह्मणी</p><p>sādhvyo brāhmaṇyaḥ.</p><p>साध्व्यो ब्राह्मण्यः |</p><p>8. devatā guruḥ = देवता गुरुः</p><p>devatā guravaḥ.</p><p>देवता गुरवः |</p><p>9. paśur dhenuḥ = पशुर्धेनुः</p><p>paśavo dhenavaḥ.</p><p>पशवो धेनवः |</p><p>10. gurvī sādhvī = गुर्वी साध्वी</p><p>gurvyaḥ sādhvyaḥ.</p><p>गुर्व्यः साध्व्यः ||</p><p>B) Bilden Sie durch Einsetzen Nominalsätze:</p><p>1. śrutis ... (veda) = श्रुतिस् ... वेद</p><p>śrutir vedaḥ.</p><p>श्रुतिर्वेदः |</p><p>2. paśus ... (dhenu) = पशुस् ... धेनु</p><p>paśur dhenuḥ.</p><p>पशुर्धेनुः |</p><p>3. devī ... (durgā, umā, indrāṇī) = देवी ... दुर्गा, उमा, इन्द्राणी</p><p>devī durgā. devy umā. devīndrāṇī.</p><p>देवी दुर्गा | देव्युमा | देवीन्द्राणी |</p><p>4. devatā ... (mīnākṣī, annapūrṇā) = देवता ... मीनाक्षी, अन्नपूर्णा</p><p>devatā mīnākṣī. devatānnapūrṇā.</p><p>देवता मीनाक्षी | देवतान्नपूर्णा |</p><p>5. śūdrā ... (itarā) = शूद्र ... इतरा</p><p>śūdretarā.</p><p>शूद्रेतरा ||</p><p>C) Übertragen Sie ins Femininum:</p><p>1. gurur brāhmaṇaḥ = गुरुर्ब्राह्मणः</p><p>gurvī brāhmaṇī.</p><p>गुर्वी ब्राह्मणी |</p><p>2. sādhur guruḥ = साधुर्गुरुः</p><p>sādhvī gurvī.</p><p>साध्वी गुर्वी |</p><p>3. kṣatriyaḥ sādhuḥ = क्षत्रियः साधुः</p><p>kṣatriyā sādhvī.</p><p>क्षत्रिया साध्वी ||</p><p>D) Übersetzen Sie ins Sanskrit:</p><p>1. Umā ist eine Göttin.</p><p>devy umā.</p><p>देव्युमा |</p><p>2. Der Veda ist śruti.</p><p>śrutir vedaḥ.</p><p>श्रुतिर्वेदः |</p><p>3. Die Lehrerinnen sind Göttinnen.</p><p>devyo gurvyaḥ.</p><p>देव्यो गुर्व्यः</p><p>4. Milchkühe sind domestizierte Tiere.</p><p>paśavo dhenavaḥ.</p><p>पशवो धेनवः |</p><p>5. Dichter sind Lehrer.</p><p>guravaḥ kavayaḥ.</p><p>गुरवः कवयः |</p><p>6. Kṣatriyas sind Zweimalgeborene.</p><p>dvijāḥ kṣatriyāḥ.</p><p>द्वि्जाः क्षत्रियाः |</p><p>7. Die heiligen Männer sind Śūdras.</p><p>śūdrāḥ sādhavaḥ.</p><p>शूद्राः साधवः ||</p><p><img src="'+n+'" alt=""><br> paśur dhenuḥ =  पशुर्धेनुः<br> Indische Zeburinder bei Bangalore<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/529395270/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/529395270/</a>. -- Zugriff am 2008-11-27. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung) ]</p>',82)])])}const l=e(t,[["render",s]]);export{g as __pageData,l as default};
